/**
 * @param {number} n
 * @returns {number[]}
 */
function solve(n) {
    // Map to store the count of ways each sum x can be formed: {x: count}
    // Keys are numbers, values are counts.
    const sums = new Map();

    // Determine the maximum possible value for b such that b^3 <= n.
    let max_b = 0;
    // Since a >= 1, if b^3 > n, then a^3 + b^3 > n.
    // We calculate floor(cbrt(n)).
    while (Math.pow(max_b + 1, 3) <= n) {
        max_b++;
    }

    // Iterate over b (the larger number, 1 <= b)
    for (let b = 1; b <= max_b; b++) {
        const b3 = b * b * b;

        // Iterate over a (the smaller number, 1 <= a <= b)
        for (let a = 1; a <= b; a++) {
            const a3 = a * a * a;
            const x = a3 + b3;

            if (x > n) {
                // Since 'a' is increasing, the sum will only get larger for this fixed 'b'.
                break; 
            }

            // Record the sum and increment the count
            sums.set(x, (sums.get(x) || 0) + 1);
        }
    }

    // Collect all 'good numbers' (where count >= 2)
    const goodNumbers = [];
    for (const [x, count] of sums.entries()) {
        if (count >= 2) {
            goodNumbers.push(x);
        }
    }

    // The result must be sorted in ascending order.
    goodNumbers.sort((a, b) => a - b);

    return goodNumbers;
}

